<?php
 namespace League\CommonMark\Extension\DisallowedRawHtml; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Renderer\BlockRendererInterface; use League\CommonMark\ElementRendererInterface; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class DisallowedRawHtmlBlockRenderer implements BlockRendererInterface, ConfigurationAwareInterface { private $htmlBlockRenderer; public function __construct(BlockRendererInterface $htmlBlockRenderer) { $this->htmlBlockRenderer = $htmlBlockRenderer; } public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { $rendered = $this->htmlBlockRenderer->render($block, $htmlRenderer, $inTightList); if ($rendered === '') { return ''; } return preg_replace('/<(\/?(?:title|textarea|style|xmp|iframe|noembed|noframes|script|plaintext)[ \/>])/i', '&lt;$1', $rendered); } public function setConfiguration(ConfigurationInterface $configuration) { if ($this->htmlBlockRenderer instanceof ConfigurationAwareInterface) { $this->htmlBlockRenderer->setConfiguration($configuration); } } } 